using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Mvc; using System.Security.Claims; using Valora.Application.Contracts; using Valora.Application.DTOs;
namespace Valora.Api.Controllers; [Authorize][ApiController] public sealed class ExportsController(IExportService exports):ControllerBase{ Guid Org=>Guid.Parse(User.FindFirstValue("organization_id")??Guid.Empty.ToString()); Guid? UserId=>Guid.TryParse(User.FindFirstValue(ClaimTypes.NameIdentifier),out var id)?id:null; [HttpPost("/exports")] public async Task<IActionResult> Create([FromBody]ExportRequest r){try{return Ok(new{ok=true,job=await exports.RequestAsync(Org,UserId,r)});}catch(InvalidOperationException ex){return StatusCode(403,new{ok=false,code=ex.Message});}} [HttpGet("/exports")] public async Task<IActionResult> List()=>Ok(new{ok=true,data=await exports.ListAsync(Org)}); [HttpGet("/exports/{id:guid}")] public async Task<IActionResult> Get(Guid id){var j=await exports.GetAsync(Org,id); return j is null?NotFound():Ok(new{ok=true,job=j});} [HttpGet("/exports/{id:guid}/download")] public async Task<IActionResult> Download(Guid id){var j=await exports.GetAsync(Org,id); return j?.ResultPayload is null?NotFound():File(System.Text.Encoding.UTF8.GetBytes(j.ResultPayload),j.ResultMimeType??"text/plain",j.ResultFileName??"export.txt");}}
